#include <bits/stdc++.h>
using namespace std;

int n,m,a[25],ans;
bitset<2003> f;
bool del[25];

void dfs(int x,int cnt){
    if(cnt==m){
        f.reset();
        f.set(0);
        for(int i=1;i<=n;i++)
            if(!del[i])
                f|=f<<a[i];
        ans=max(ans,(int)f.count()-1);
        return;
    }
    if(x>n)
        return;
    if(n-x+1>m-cnt)
        dfs(x+1,cnt);
    del[x]=1;
    dfs(x+1,cnt+1);
    del[x]=0;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    dfs(1,0);
    printf("%d",ans);
    return 0;
}
